impl Solution { pub fn number_of_rounds(login_time: String, logout_time: String) -> i32 { let (mut black_in, mut black_out) = (login_time[..2].parse::<i32>().unwrap() * 60 + login_time[3..].parse::<i32>().unwrap(), logout_time[..2].parse::<i32>().unwrap() * 60 + logout_time[3..].parse::<i32>().unwrap()); if black_out < black_in { black_out += 1440; } ((black_out / 15) - ((black_in + 14) / 15)).max(0) } }